```
#include <iostream>
using namespace std;

int main() {
   int arr[] = { 5, 2, 8, 1, 6 };
   int n = sizeof(arr) / sizeof(arr[0]);

   // Bubble sort algorithm
   for (int I = 0; I < n - 1; i++) {
      for (int j = 0; j < n - I - 1; j++) {
         if (arr[j] < arr[j + 1]) {
            int temp = arr[j];
            arr[j] = arr[j + 1];
            arr[j + 1] = temp;
         }
      }
   }

   // Print the sorted array in descending order
   cout << "Sorted array in descending order: ";
   for (int I = 0; I < n; i++)
      cout << arr[i] << " ";

   return 0;
}
