Void reverseArray(int arr[], int size) {
   // handle empty array and size 1 array
   if(size == 0 || size == 1) {
      return;
   }

   // initialize variables for swapping
   int left = 0;
   int right = size - 1;

   // loop through array and swap elements in-place
   while(left < right) {
      int temp = arr[left];
      arr[left] = arr[right];
      arr[right] = temp;
      left++;
      right--;
   }
